@* Displays a single task with priority badge and move buttons *@

<div class="task-card">
    <div class="task-header">
        <span class="task-title">@Task.Title</span>
        <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    </div>
    <div class="task-meta">
        <span class="task-assignee">@Task.Assignee</span>
        <span class="task-due">@Task.DueDate.ToString("MMM dd")</span>
    </div>
    <div class="task-actions">
        @if (ShowMoveLeft)
        {
            <button class="btn-move" @onclick="OnMoveLeftClick" disabled="@IsMoving">← Move Left</button>
        }
        @if (ShowMoveRight)
        {
            <button class="btn-move" @onclick="OnMoveRightClick" disabled="@IsMoving">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback<int> OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback<int> OnMoveRight { get; set; }

    private bool IsMoving;

    private async System.Threading.Tasks.Task OnMoveLeftClick()
    {
        IsMoving = true;
        await OnMoveLeft.InvokeAsync(Task.Id);
        IsMoving = false;
    }

    private async System.Threading.Tasks.Task OnMoveRightClick()
    {
        IsMoving = true;
        await OnMoveRight.InvokeAsync(Task.Id);
        IsMoving = false;
    }
}

@* Inline form to create a new task within a column *@

@if (!IsVisible)
{
    <button class="btn-add-task" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="add-task-form">
        <input type="text" placeholder="Title" @bind="Title" />
        <input type="text" placeholder="Assignee" @bind="Assignee" />
        <select @bind="Priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
        <input type="date" @bind="DueDate" />
        <div class="form-actions">
            <button class="btn-save" @onclick="Save" disabled="@IsSaving">Save</button>
            <button class="btn-cancel" @onclick="Cancel">Cancel</button>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }

    private bool IsVisible;
    private bool IsSaving;
    private string Title = string.Empty;
    private string Assignee = string.Empty;
    private string Priority = "Medium";
    private DateTime DueDate = DateTime.Today.AddDays(7);

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        IsVisible = false;
        ResetForm();
    }

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(Title)) return;

        IsSaving = true;
        await OnSave.InvokeAsync((Title, Assignee, Priority, DueDate));
        IsSaving = false;
        IsVisible = false;
        ResetForm();
    }

    private void ResetForm()
    {
        Title = string.Empty;
        Assignee = string.Empty;
        Priority = "Medium";
        DueDate = DateTime.Today.AddDays(7);
    }
}

@* Search input that filters tasks by title *@

<div class="search-bar">
    <input type="text" placeholder="Search tasks by title…" value="@SearchText"
           @oninput="OnInput" />
</div>

@code {
    [Parameter]
    public string SearchText { get; set; } = string.Empty;

    [Parameter, EditorRequired]
    public EventCallback<string> OnSearchChanged { get; set; }

    private async Task OnInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? string.Empty);
    }
}

@* A single Kanban column displaying filtered tasks and an add-task form *@

<div class="board-column">
    <div class="column-header">
        <h3>@ColumnName</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      OnMoveLeft="OnMoveLeft"
                      OnMoveRight="OnMoveRight" />
        }
    </div>

    <div class="column-footer">
        <AddTaskForm OnSave="OnAddTask" />
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string ColumnName { get; set; } = string.Empty;

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = new();

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback<int> OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback<int> OnMoveRight { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnAddTask { get; set; }
}

