{"file_text": "@page "/board"
@rendermode InteractiveServer
@using sv_33e1b50110824887a9785b9a76afac5b.Components.Board
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

@if (isLoading)
{
    <p class="board-loading">Loading board…</p>
}
else if (errorMessage is not null)
{
    <div class="board-error">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="board-columns">
        <BoardColumn ColumnName="To Do"
                     Tasks="GetFiltered("To Do")"
                     ShowMoveLeft="false"
                     ShowMoveRight="true"
                     OnMoveRight="id => MoveTask(id, "In Progress")"
                     OnAddTask="args => AddTask(args, "To Do")" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="GetFiltered("In Progress")"
                     ShowMoveLeft="true"
                     ShowMoveRight="true"
                     OnMoveLeft="id => MoveTask(id, "To Do")"
                     OnMoveRight="id => MoveTask(id, "Done")"
                     OnAddTask="args => AddTask(args, "In Progress")" />

        <BoardColumn ColumnName="Done"
                     Tasks="GetFiltered("Done")"
                     ShowMoveLeft="true"
                     ShowMoveRight="false"
                     OnMoveLeft="id => MoveTask(id, "In Progress")"
                     OnAddTask="args => AddTask(args, "Done")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFiltered(string status)
    {
        IEnumerable<TaskItem> items = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            items = items.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return items.ToList();
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                var old = allTasks[idx];
                allTasks[idx] = old with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task AddTask((string Title, string Assignee, string Priority, DateTime DueDate) args, string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            allTasks.Add(created with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}
